// Tomamos el cuerpo real del webhook
const body = $json.body || $json;

// Navegamos la estructura de WhatsApp
const entry  = body.entry?.[0];
const change = entry?.changes?.[0];
const value  = change?.value;
const msg    = value?.messages?.[0];

if (!msg) {
  return {
    valid_msg: false,
  };
}

const from    = msg.from;
const msgType = msg.type || 'text';

// NUEVO: metadata del número de negocio
const phoneNumberId       = value?.metadata?.phone_number_id || null;
const waBusinessNumber    = value?.metadata?.display_phone_number || null;

// Detectar media_id para audio / imagen / video
let mediaId = null;
if (msgType === 'audio' || msgType === 'voice') {
  mediaId = msg.audio?.id || msg.voice?.id || null;
} else if (msgType === 'image') {
  mediaId = msg.image?.id || null;
} else if (msgType === 'video') {
  mediaId = msg.video?.id || null;
}

const waName =
  msg.sender_name
  || (Array.isArray(value?.contacts) && value.contacts[0]?.profile?.name)
  || 'Colega';

return {
  valid_msg: true,
  phone_raw: from,
  phone: from,
  wa_name: waName,
  msg_type: msgType,
  whatsapp_text: msg.text?.body || '',
  media_id: mediaId,
  inbound_raw: $json,
  phone_number_id: phoneNumberId,      // NUEVO
  wa_business_number: waBusinessNumber // NUEVO
};

return {
  text: 'El cliente envió una imagen por WhatsApp. Pedile en el chat que te cuente brevemente qué muestra la foto o qué necesita.',
};

return {
  text: 'El cliente envió un video por WhatsApp. Respondé como closer y pedile que resuma en texto qué necesita o qué muestra el video.',
};

// Tomamos el objeto base del nodo que parsea el webhook de WhatsApp
const base = $node["Patch Phone For Sandbox"].json;

// En este branch normalmente viene 1 ítem (texto, transcripción, etc.)
const inputs = $input.all();
const branch = inputs[0]?.json || {};

// 1) Texto “crudo”
// - Si algún nodo previo agregó `text` (ej: transcripción de audio), lo usamos.
// - Si no, usamos el `whatsapp_text` original del parse.
let coreText = branch.text || base.whatsapp_text || '';
coreText = String(coreText || '').trim();

// 2) Prefijo según tipo de mensaje
let prefix = '';

if (base.msg_type === 'audio' || base.msg_type === 'voice') {
  prefix = '[AUDIO] ';
} else if (base.msg_type === 'image') {
  prefix = '[IMAGEN] ';
} else if (base.msg_type === 'video') {
  prefix = '[VIDEO] ';
}

// 3) Texto final para guardar en la BD / logs
const finalText = (prefix + coreText).trim();

// 4) Versión “limpia” para checks de STOP / SPAM, intents, etc.
let cleanText = finalText
  .toLowerCase()
  .normalize('NFD')                 // separa caracteres con tilde
  .replace(/[\u0300-\u036f]/g, '')  // elimina las tildes
  .replace(/\s+/g, ' ')             // colapsa espacios múltiples
  .trim();

return {
  // Traemos todo lo del parse original
  ...base,
  // Traemos también cualquier cosa que haya agregado el branch (por si después sumás más campos)
  ...branch,
  // Campos normalizados que va a usar el resto del flujo
  final_input: finalText,
  clean_text: cleanText,
};

