// El nodo anterior (Nova – Editor) devuelve algo como:
// { "text": "{ \"reply\": \"...\", \"lead_status\": \"...\", ... }" }
// o, si Simplify está apagado, en message.content.

let reply = '';
let leadStatus = 'WORKING';
let conversationStage = 'DISCOVERY';
let painPoints = [];
let interestLevel = 'MED';
let tags = [];
let nextFollowupDays = 2;

const data = $json;

// 1) Detectar fuente principal del texto bruto
let rawContent = '';

if (typeof data.text === 'string' && data.text.trim() !== '') {
  rawContent = data.text;
} else if (data.message?.content) {
  rawContent = data.message.content;
} else if (typeof data === 'string') {
  rawContent = data;
}

// 2) Normalizar un poco el contenido
if (typeof rawContent !== 'string') {
  rawContent = String(rawContent || '');
}
rawContent = rawContent.trim();

// 2.1) Si viene envuelto en ``` o ```json, los sacamos
if (rawContent.startsWith('```')) {
  // Sacar primera línea ``` o ```json
  rawContent = rawContent.replace(/^```[a-zA-Z0-9]*\s*/, '');
  // Sacar ``` final
  if (rawContent.endsWith('```')) {
    rawContent = rawContent.slice(0, -3).trim();
  }
}

// 3) Intentar parsear JSON
let parsed;

function tryParse(str) {
  try {
    return JSON.parse(str);
  } catch (e) {
    return null;
  }
}

// Primer intento: todo el string
parsed = tryParse(rawContent);

// Segundo intento: si falla, buscar el primer '{' y el último '}'
if (!parsed) {
  const first = rawContent.indexOf('{');
  const last = rawContent.lastIndexOf('}');
  if (first !== -1 && last !== -1 && last > first) {
    const jsonSlice = rawContent.slice(first, last + 1);
    parsed = tryParse(jsonSlice);
  }
}

// Si sigue fallando, usamos el contenido crudo como reply
if (!parsed) {
  parsed = { reply: rawContent };
}

// 4) Extraer campos con defaults
if (typeof parsed.reply === 'string') {
  reply = parsed.reply;
} else if (typeof rawContent === 'string' && rawContent.trim() !== '') {
  reply = rawContent;
} else {
  reply =
    'Gracias por escribirme. Contame en una frase cómo estás vendiendo hoy y qué te gustaría mejorar, así veo si NovaVision te puede sumar valor.';
}

if (typeof parsed.lead_status === 'string') {
  leadStatus = parsed.lead_status;
}
if (typeof parsed.conversation_stage === 'string') {
  conversationStage = parsed.conversation_stage;
}
if (Array.isArray(parsed.pain_points)) {
  painPoints = parsed.pain_points;
}
if (typeof parsed.interest_level === 'string') {
  interestLevel = parsed.interest_level;
}
if (Array.isArray(parsed.tags)) {
  tags = parsed.tags;
}
if (typeof parsed.next_followup_days === 'number') {
  nextFollowupDays = parsed.next_followup_days;
}

// -------------------------------------------------------------------
// 5) Helpers y contexto del inbound
// -------------------------------------------------------------------
const normalizeForCompare = (str) =>
  String(str || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '') // saca tildes
    .replace(/[^a-z0-9ñü\s]/gi, ' ') // limpia signos raros
    .replace(/\s+/g, ' ')
    .trim();

const inboundClean =
  normalizeForCompare($node['Normalize Input'].json.clean_text || '');

// --- BLOQUE NUEVO: detectar rubros ilegales / sexuales explícitos ---
const illegalSexBizRegex =
  /(prostitucion|prostitución|servicios sexuales|trabajo sexual|escort|acompanante|acompañante)/;

const isIllegalSexBiz = illegalSexBizRegex.test(inboundClean);

if (isIllegalSexBiz) {
  reply =
    'Gracias por escribir. NovaVision está pensada para negocios que venden productos o servicios legales y formales (tiendas online, servicios profesionales, etc.). ' +
    'Por el tipo de actividad que comentás, no somos la plataforma indicada, así que prefiero dejar la conversación acá. ' +
    'Si más adelante tenés otro emprendimiento que sí entre en ese marco, escribime tranqui y lo vemos.';

  leadStatus = 'LOST';
  conversationStage = 'DISCOVERY';
  interestLevel = 'LOW';
  nextFollowupDays = 0;

  if (!Array.isArray(tags)) tags = [];
  if (!tags.includes('illegal_vertical')) tags.push('illegal_vertical');

  return {
    reply,
    lead_status: leadStatus,
    conversation_stage: conversationStage,
    pain_points: painPoints,
    interest_level: interestLevel,
    tags,
    next_followup_days: nextFollowupDays,
  };
}


// detección básica de intención de precio
const wantsPrice =
  inboundClean.includes('precio') ||
  inboundClean.includes('precios') ||
  inboundClean.includes('costo') ||
  inboundClean.includes('costos') ||
  inboundClean.includes('cuanto sale') ||
  inboundClean.includes('cuánto sale') ||
  inboundClean.includes('cuanto cuesta') ||
  inboundClean.includes('cuánto cuesta') ||
  inboundClean.includes('tarifa') ||
  inboundClean.includes('tarifas') ||
  inboundClean.includes('valor mensual') ||
  inboundClean.includes('mensual');

// detección básica de intención de demo / llamada / reunión / hablar con humano
const wantsDemo =
  inboundClean.includes('demo') ||
  inboundClean.includes('reunion') ||
  inboundClean.includes('reunión') ||
  inboundClean.includes('llamada') ||
  inboundClean.includes('videollamada') ||
  inboundClean.includes('agenda') ||
  inboundClean.includes('agendar') ||
  inboundClean.includes('reunirse') ||
  inboundClean.includes('hablar con alguien') ||
  inboundClean.includes('hablarlo con alguien') ||
  inboundClean.includes('hablar con vos') ||
  inboundClean.includes('charlar con alguien') ||
  inboundClean.includes('charlarlo') ||
  inboundClean.includes('quiero hablar') ||
  inboundClean.includes('me llamen') ||
  inboundClean.includes('me llames') ||
  inboundClean.includes('llamarme') ||
  inboundClean.includes('contacten') ||
  inboundClean.includes('contactarme');

// aceptación genérica tipo "si dale", "dale", "ok dale"
const isAcceptance =
  inboundClean === 'si' ||
  inboundClean === 'dale' ||
  inboundClean === 'ok' ||
  inboundClean.startsWith('si dale') ||
  inboundClean.startsWith('si, dale') ||
  inboundClean.includes('si dale') ||
  inboundClean.includes('dale si');

// -------------------------------------------------------------------
// 6) Último mensaje del bot desde WA History + si alguna vez dijo "no lo sé"
// -------------------------------------------------------------------
let lastBotMsg = '';
let userEverSaidNoSeTimeframe = false;

try {
  const histRaw = $node['Get WA History'].json;
  let history = [];

  if (Array.isArray(histRaw)) {
    history = histRaw;
  } else if (histRaw && Array.isArray(histRaw.data)) {
    history = histRaw.data;
  } else if (histRaw && Array.isArray(histRaw.records)) {
    history = histRaw.records;
  }

  if (history.length > 0) {
    // Recorremos desde el final para tomar el ÚLTIMO BOT real
    for (let i = history.length - 1; i >= 0; i--) {
      const h = history[i];
  if (
  h &&
  (h.direction === 'BOT' || h.direction === 'OUTBOUND') &&
  typeof h.message_text === 'string'
) {
  lastBotMsg = h.message_text;
}

    }

    // Marcar si en algún INBOUND anterior el cliente dijo "no lo se / no se"
    for (let i = history.length - 1; i >= 0; i--) {
      const h = history[i];
      if (!h || h.direction !== 'INBOUND') continue;

      const msgNorm = normalizeForCompare(h.message_text || '');
      const saidNoSe =
        msgNorm.includes('no lo se') || msgNorm.includes('no se');
      const mentionsTimeWord =
        msgNorm.includes('cuando') ||
        msgNorm.includes('tiempo') ||
        msgNorm.includes('fecha');

      // Solo marcamos “no sé” para plazos si además habla de tiempo/fecha
      if (saidNoSe && mentionsTimeWord) {
        userEverSaidNoSeTimeframe = true;
        break;
      }
    }

  }
} catch (e) {
  lastBotMsg = '';
  userEverSaidNoSeTimeframe = false;
}

const lastBotNorm = normalizeForCompare(lastBotMsg);
const replyNorm = normalizeForCompare(reply);


// -------------------------------------------------------------------
// 6.1) ¿El cliente está respondiendo horario para demo/llamada?
// -------------------------------------------------------------------
const inboundMentionsTime =
  inboundClean.includes('manana') ||
  inboundClean.includes('mañana') ||
  inboundClean.includes('tarde') ||
  inboundClean.includes('noche') ||
  inboundClean.includes('lunes') ||
  inboundClean.includes('martes') ||
  inboundClean.includes('miercoles') ||
  inboundClean.includes('miércoles') ||
  inboundClean.includes('jueves') ||
  inboundClean.includes('viernes') ||
  inboundClean.includes('sabado') ||
  inboundClean.includes('sábado') ||
  inboundClean.includes('domingo') ||
  inboundClean.includes('semana que viene') ||
  inboundClean.includes('proxima semana') ||
  inboundClean.includes('próxima semana') ||
  inboundClean.includes('fin de semana');

const lastBotWasScheduling =
  lastBotNorm.includes('llamada') ||
  lastBotNorm.includes('demo') ||
  lastBotNorm.includes('agenda') ||
  lastBotNorm.includes('agendar');

const isSchedulingAnswer = inboundMentionsTime && lastBotWasScheduling;

// -------------------------------------------------------------------
// 6.2) Aceptación directa de demo / ayuda con plan
// -------------------------------------------------------------------
const lastBotAskedDemoOrPlan =
  lastBotNorm.includes('demo') ||
  lastBotNorm.includes('coordinamos una demo') ||
  lastBotNorm.includes('coordinamos una llamada') ||
  lastBotNorm.includes('te ayudo a ver si ese plan') ||
  lastBotNorm.includes('te ayudo a ver si ese') ||
  lastBotNorm.includes('te puedo mostrar un ejemplo');

// Si el cliente dice "si / si dale / ok dale" después de un CTA de demo,
// NO seguimos en discovery: lo mandamos directo a la página de lead.
if (isAcceptance && lastBotAskedDemoOrPlan) {
  reply =
    'Genial, avancemos entonces. Para coordinar la demo sin marearte con ida y vuelta por WhatsApp, lo más simple es que entres acá, mires el video corto y elijas día y horario que te quede cómodo:\n' +
    'https://novavision.lat/lead\n\n' +
    'Completás esos datos y ahí seguimos con una demo bien aplicada a tu negocio. ¿Te queda cómodo completarlo hoy?';

  if (leadStatus === 'WORKING') {
    leadStatus = 'QUALIFIED';
  }
  conversationStage = 'DEMO_OFFERED';

  if (interestLevel === 'LOW') {
    interestLevel = 'MED';
  } else {
    interestLevel = 'HIGH';
  }

  if (!Array.isArray(tags)) tags = [];
  if (!tags.includes('closing_cta')) tags.push('closing_cta');
  if (!tags.includes('cta_lead_page')) tags.push('cta_lead_page');
}



// -------------------------------------------------------------------
// 7) Marcar interés por preguntas de precio
// -------------------------------------------------------------------
if (!Array.isArray(tags)) {
  tags = [];
}

if (wantsPrice) {
  if (!tags.includes('price_question')) {
    tags.push('price_question');
  }
  // si pregunta precios, por defecto lo tratamos como interés MED/HIGH
  if (interestLevel === 'LOW') {
    interestLevel = 'MED';
  } else if (interestLevel === 'MED') {
    interestLevel = 'HIGH';
  }
}

// -------------------------------------------------------------------
// 8) Guardrail para respuestas tipo "Todo / las tres / un poco de todo"
//     -> en vez de seguir encuestando, ir a CTA de demo/call
// -------------------------------------------------------------------
const saidTodo =
  inboundClean.includes('todo la verdad') ||
  inboundClean.includes('todo, la verdad') ||
  inboundClean.includes('las tres') ||
  inboundClean.includes('un poco de todo') ||
  /\btodo\b/.test(inboundClean);

if (saidTodo) {
  const replyLower = reply.toLowerCase();

  const isMultiChoiceLoop =
    replyLower.includes('que es lo que mas te gustaria') ||
    replyLower.includes('qué es lo que más te gustaría') ||
    replyLower.includes('que te gustaria mejorar') ||
    replyLower.includes('qué te gustaría mejorar') ||
    replyLower.includes(
      'que es lo que mas te gustaria ordenar primero'
    ) ||
    replyLower.includes(
      'qué es lo que más te gustaría ordenar primero'
    );

  // Solo intervenimos si venís de una pregunta tipo "elegí 1 de 3 dolores"
  if (isMultiChoiceLoop) {
    reply =
      'OK, se nota que hoy te está pesando todo: stock, presentación y el tiempo de estar respondiendo.\n' +
      'NovaVision justo apunta a ordenar catálogo, stock y pedidos para que tus clientes puedan entrar, ver y comprar directo sin escribirte por cada cosa.\n' +
      'Para no seguir dándote vueltas por WhatsApp, lo más útil es una llamada corta donde veamos tu caso y si tiene sentido avanzar ahora. ¿Te serviría coordinar una demo gratuita de 15 minutos esta semana o por ahora preferís solo ir viendo info por acá?';

    // Si dijo "todo", es un lead con dolor real -> subimos interés
    if (interestLevel === 'LOW') {
      interestLevel = 'MED';
    } else {
      interestLevel = 'HIGH';
    }

    if (leadStatus === 'WORKING') {
      leadStatus = 'QUALIFIED';
    }

    conversationStage = 'DEMO_OFFERED';

    if (!Array.isArray(tags)) tags = [];
    if (!tags.includes('closing_cta')) {
      tags.push('closing_cta');
    }
  }
}

// -------------------------------------------------------------------
// 8.1) No repetir preguntas de discovery tipo "¿qué te complica más...?"
// -------------------------------------------------------------------
function isDiscoveryMultiChoiceQuestion(text) {
  const t = normalizeForCompare(text || '');
  if (!t) return false;

  const hasDiscoveryCue =
    t.includes('que sentis que te complica mas') ||
    t.includes('que sentis que hoy te complica mas') ||
    t.includes('que es lo que mas te gustaria mejorar') ||
    t.includes('que es lo que mas te gustaria ordenar') ||
    t.includes('cual sentis que te pesa mas');

  const hasClassicOptions =
    (t.includes('stock') && t.includes('pedido')) ||
    (t.includes('stock') && t.includes('pedidos')) ||
    (t.includes('pedidos') && t.includes('tiempo'));

  return hasDiscoveryCue || hasClassicOptions;
}

let discoveryAskedBefore = false;
try {
  const histRawDisc = $node['Get WA History'].json;
  let histDisc = [];

  if (Array.isArray(histRawDisc)) histDisc = histRawDisc;
  else if (histRawDisc && Array.isArray(histRawDisc.data)) histDisc = histRawDisc.data;
  else if (histRawDisc && Array.isArray(histRawDisc.records)) histDisc = histRawDisc.records;

  for (const h of histDisc) {
    if (!h || h.direction !== 'BOT') continue;
    if (isDiscoveryMultiChoiceQuestion(h.message_text)) {
      discoveryAskedBefore = true;
      break;
    }
  }
} catch (e) {
  discoveryAskedBefore = false;
}

const replyIsDiscoveryMultiChoice = isDiscoveryMultiChoiceQuestion(reply);

if (discoveryAskedBefore && replyIsDiscoveryMultiChoice) {
  // Si ya hicimos esta encuesta antes, no la repetimos: avanzamos de etapa
  reply =
    'Con lo que ya me contaste se entiende bien el panorama, no tiene sentido seguir con mil preguntas.\n' +
    'Lo que puedo hacer ahora es mostrarte en simple qué te ordenaría NovaVision (cómo se ve tu tienda, cómo entran los pedidos y cómo podrías aprovechar mejor lo online) y ver si tiene sentido que avancemos.\n' +
    '¿Preferís que te lo resuma en pocas líneas por acá o pasamos directo a coordinar una demo corta para verlo aplicado a tu caso?';

  if (conversationStage === 'DISCOVERY') {
    conversationStage = 'PROFUNDIZAR DOLORES';
  }
  if (interestLevel === 'LOW') {
    interestLevel = 'MED';
  }
}


// -------------------------------------------------------------------
// 9) Similaridad más inteligente para detectar loop de pitch
// -------------------------------------------------------------------
function similarity(a, b) {
  const aTokens = normalizeForCompare(a).split(' ').filter(Boolean);
  const bTokens = normalizeForCompare(b).split(' ').filter(Boolean);
  if (aTokens.length === 0 || bTokens.length === 0) return 0;

  const aSet = new Set(aTokens);
  const bSet = new Set(bTokens);

  let intersection = 0;
  for (const t of aSet) {
    if (bSet.has(t)) intersection++;
  }
  const unionSize = new Set([...aSet, ...bSet]).size || 1;
  return intersection / unionSize;
}

const loopSimilarity = similarity(lastBotMsg, reply);
const looksLikeLoop = loopSimilarity >= 0.75;

const lastBotWasPitch =
  lastBotNorm.includes('vendes remeras') ||
  lastBotNorm.includes('vendes remera') ||
  lastBotNorm.includes('vendés remeras') ||
  lastBotNorm.includes('tienda online') ||
  lastBotNorm.includes('te muestro un ejemplo rapido') ||
  lastBotNorm.includes('te muestro un ejemplo rápido') ||
  lastBotNorm.includes('te gustaria que te muestre') ||
  lastBotNorm.includes('te gustaría que te muestre');

// Si el cliente dice "si dale" y el modelo repite casi el mismo pitch,
// forzamos avanzar de etapa (no repetir la misma perorata).
if (isAcceptance && looksLikeLoop && lastBotWasPitch) {
  reply =
    'Genial, avancemos entonces. Lo que puedo hacer ahora es mostrarte un ejemplo concreto de cómo se vería tu tienda y cómo funcionaría con lo que vendés hoy.\n\n' +
    '¿Preferís que te envíe un ejemplo por WhatsApp ahora o coordinamos una mini demo de 15 minutos para verlo en detalle?';

  leadStatus = 'QUALIFIED';
  conversationStage = 'DEMO_OFFERED';
  if (interestLevel === 'LOW') {
    interestLevel = 'MED';
  } else {
    interestLevel = 'HIGH';
  }
}

// -------------------------------------------------------------------
// 10) Guardrail anti-loop genérico (texto casi igual al último BOT)
// -------------------------------------------------------------------
let isSameAsLastBot = false;
if (lastBotNorm && replyNorm) {
  const lenA = lastBotNorm.length;
  const lenB = replyNorm.length;
  const shorter = lenA <= lenB ? lastBotNorm : replyNorm;
  const longer = lenA <= lenB ? replyNorm : lastBotNorm;

  if (longer.includes(shorter)) {
    const ratio = shorter.length / longer.length;
    if (ratio > 0.8) {
      isSameAsLastBot = true;
    }
  }
}

if (isSameAsLastBot) {
  if (wantsPrice) {
    // Si el cliente está pidiendo precio y el bot repite lo mismo que antes,
    // forzamos un mensaje que hable de costos en vez de seguir dando vueltas.
    reply =
      'Bien, vayamos directo a lo que te importa: los costos. Tenemos distintos planes según el tamaño y la complejidad de tu negocio, pero para alguien que vende por redes suele encajar un plan inicial donde ya tenés tienda, catálogo y gestión de pedidos.\n' +
      'Hoy esos planes están pensados para que sean accesibles para un emprendimiento y se ajustan mejor en una llamada rápida donde vemos tu caso.\n' +
      '¿Te sirve que te oriente en una demo corta y ahí te damos el rango concreto según cómo estés trabajando hoy?';
  } else {
    // No es precio, pero igual está repitiendo: empujamos a siguiente paso
    reply =
      'Quedó claro lo que me contaste, no quiero seguir repitiendo lo mismo.\n' +
      'Con lo que ya sabemos de tu negocio, el siguiente paso lógico es mostrarte cómo se vería tu tienda y revisar números en concreto.\n' +
      '¿Te serviría una llamada corta para ver un ejemplo y terminar de ver si encaja para vos?';
  }
}

// -------------------------------------------------------------------
// 11) Guardrail de precio: si piden precio y la respuesta NO habla de precio
// -------------------------------------------------------------------
if (wantsPrice) {
  const replyLower = reply.toLowerCase();
  const talksAboutPrice =
    replyLower.includes('precio') ||
    replyLower.includes('precios') ||
    replyLower.includes('costo') ||
    replyLower.includes('costos') ||
    replyLower.includes('cuanto sale') ||
    replyLower.includes('cuánto sale') ||
    replyLower.includes('cuanto cuesta') ||
    replyLower.includes('cuánto cuesta') ||
    replyLower.includes('tarifa') ||
    replyLower.includes('tarifas') ||
    replyLower.includes('valor mensual') ||
    replyLower.includes('por mes') ||
    replyLower.includes('mensual');

  if (!talksAboutPrice) {
    // Fallback: respuesta directa, precios públicos + plan orientativo
    reply =
      'Tiene todo el sentido que quieras ver los costos.\n' +
      'Los precios de NovaVision son públicos y los podés ver siempre actualizados en la página principal: https://novavision.lat.\n' +
      'Por lo que venimos charlando, mucha gente en una situación parecida a la tuya suele arrancar con un plan para emprendedores donde ya tenés tienda online, catálogo y cobros integrados.\n' +
      'Si querés, te ayudo a ver si ese plan te encaja y, si te cierra, coordinamos una demo corta para verlo aplicado a tu negocio.';
  }
}

// -------------------------------------------------------------------
// 11.1) Si está respondiendo horario, no sigas con pitch infinito
// -------------------------------------------------------------------
if (isSchedulingAnswer) {
  reply =
    'Genial, te queda mejor a la tarde. Para no marearte coordinando horarios por acá, tenemos una página donde podés ver un video corto, contarnos un poco más de tu negocio y elegir día y horario para la demo cuando te quede cómodo:\n' +
    'https://novavision.lat/lead\n\n' +
    'Ahí nos llega toda la info y seguimos por ahí. ¿Te sirve?';

  if (!Array.isArray(tags)) tags = [];
  if (!tags.includes('cta_lead_page')) tags.push('cta_lead_page');

  if (leadStatus === 'WORKING') {
    leadStatus = 'QUALIFIED';
  }
  conversationStage = 'DEMO_OFFERED';
  if (interestLevel === 'LOW') {
    interestLevel = 'MED';
  } else {
    interestLevel = 'HIGH';
  }
}

// -------------------------------------------------------------------
// 11.2) Respuesta tipo "no lo sé" a la pregunta de plazo
//      -> cortar el loop y mandar directo a la lead page
// -------------------------------------------------------------------

// Detectar variantes de "no lo sé"
const inboundSaysNoSe =
  inboundClean === 'no lo se' ||
  inboundClean === 'no se' ||
  inboundClean.startsWith('no lo se ') ||
  inboundClean.startsWith('no se ');

// Detectar preguntas de plazo / urgencia, no solo "para cuando..."
const timeframePhrases = [
  'para cuando te gustaria tener',
  'para cuando te gustaria la tienda',
  'para cuando te gustaria tener la tienda',
  'cuando te gustaria poder tener esto funcionando',
  'cuando te gustaria tener esto funcionando',
  'cuando te gustaria tener algo asi funcionando',
  'que tan urgente es',
  'que tan urgente lo ves',
];

const lastBotAskedTimeframe = timeframePhrases.some((p) =>
  lastBotNorm.includes(p)
);

const replyAsksTimeframe = timeframePhrases.some((p) =>
  replyNorm.includes(p)
);


// Si el cliente dice (o dijo alguna vez) "no lo se / no se" y el bot está en modo plazo,
// cortamos el tema tiempo y lo llevamos directo a la lead page.
const userRejectedTimeframe = inboundSaysNoSe || userEverSaidNoSeTimeframe;

if (userRejectedTimeframe && (lastBotAskedTimeframe || replyAsksTimeframe)) {
  reply =
    'Está perfecto si todavía no tenés una fecha clara. Lo importante es ver si este tipo de tienda te suma de verdad.\n' +
    'Para eso, lo más útil es que veas un ejemplo y agendes una demo cuando te quede cómodo desde acá:\n' +
    'https://novavision.lat/lead\n\n' +
    'Ahí contás un poco de tu negocio y elegís el horario que mejor te quede. ¿Te animás a completarlo y después seguimos por ahí?';

  if (leadStatus === 'WORKING') {
    leadStatus = 'QUALIFIED';
  }
  conversationStage = 'DEMO_OFFERED';

  if (!Array.isArray(tags)) tags = [];
  if (!tags.includes('closing_cta')) tags.push('closing_cta');
  if (!tags.includes('cta_lead_page')) tags.push('cta_lead_page');

  if (interestLevel === 'LOW') {
    interestLevel = 'MED';
  } else {
    interestLevel = 'HIGH';
  }
}

// -------------------------------------------------------------------
// 11.3) Si el cliente ya tiene el link y solo agradece, no sigas empujando
// -------------------------------------------------------------------
const inboundSaysThanksOrClose =
  inboundClean === 'gracias' ||
  inboundClean === 'muchas gracias' ||
  inboundClean === 'dale gracias' ||
  inboundClean.includes('gracias') ||
  inboundClean.includes('listo gracias') ||
  inboundClean.includes('ya lo complete') ||
  inboundClean.includes('ya lo completé') ||
  inboundClean.includes('ya lo voy a completar') ||
  inboundClean.includes('ya lo veo') ||
  inboundClean.includes('ya lo voy a ver');

let historyContainsLeadPage = false;
try {
  const histRaw2 = $node['Get WA History'].json;
  let history2 = [];

  if (Array.isArray(histRaw2)) history2 = histRaw2;
  else if (histRaw2 && Array.isArray(histRaw2.data)) history2 = histRaw2.data;
  else if (histRaw2 && Array.isArray(histRaw2.records)) history2 = histRaw2.records;

  historyContainsLeadPage = history2.some(
    (h) =>
      h &&
      typeof h.message_text === 'string' &&
      /novavision\.lat\/lead/.test(h.message_text)
  );
} catch (e) {
  historyContainsLeadPage = false;
}

const lateStageForClosing =
  historyContainsLeadPage ||
  (Array.isArray(tags) && tags.includes('cta_lead_page')) ||
  ['DEMO_OFFERED', 'DEMO_BOOKED', 'CLOSING'].includes(conversationStage);

if (inboundSaysThanksOrClose && lateStageForClosing) {
  reply =
    'Genial, gracias a vos. Cuando completes el formulario te llega la info y seguimos desde ahí. Si te surge alguna duda después de verlo, escribime por acá y lo vemos.';

  if (leadStatus === 'WORKING') {
    leadStatus = 'QUALIFIED';
  }

  // Marcamos que ya está en etapa de cierre / seguimiento
  if (!['DEMO_BOOKED', 'WON', 'LOST'].includes(conversationStage)) {
    conversationStage = 'CLOSING';
  }

  if (!Array.isArray(tags)) tags = [];
  if (!tags.includes('cta_lead_page') && historyContainsLeadPage) {
    tags.push('cta_lead_page');
  }
}



// -------------------------------------------------------------------
// 12) CTA página de lead (video + formulario + demo)
// -------------------------------------------------------------------
const replyHasLeadPage = /novavision\.lat\/lead/.test(reply);

// NUEVO: exigimos señales más fuertes y que NO sea el primer mensaje
// Para eso, reusá la history que calculaste antes:
let historyLen = 0;
try {
  const histRaw = $node['Get WA History'].json;
  let history = [];

  if (Array.isArray(histRaw)) history = histRaw;
  else if (histRaw && Array.isArray(histRaw.data)) history = histRaw.data;
  else if (histRaw && Array.isArray(histRaw.records)) history = histRaw.records;

  historyLen = history.length;
} catch (e) {
  historyLen = 0;
}

const inboundIsThankYou =
  inboundClean.includes('gracias') ||
  inboundClean.includes('dale gracias') ||
  inboundClean.includes('listo gracias') ||
  inboundClean.includes('ya lo complete') ||
  inboundClean.includes('ya lo completé') ||
  inboundClean.includes('ya lo voy a completar');

const shouldPushLeadPage =
  !inboundIsThankYou &&
  historyLen >= 2 && // nunca en el primer mensaje real
  (
    wantsDemo ||
    ['QUALIFIED', 'WON'].includes(leadStatus) ||
    ['DEMO_OFFERED', 'DEMO_BOOKED', 'CLOSING'].includes(conversationStage)
  );


if (shouldPushLeadPage && !replyHasLeadPage) {
  reply +=
    '\n\nPara verlo bien concreto y sin marearte por acá, tenemos una página donde podés ver un video corto, completar un formulario y agendar una demo cuando te quede cómodo:\n' +
    'https://novavision.lat/lead';

  if (!Array.isArray(tags)) tags = [];
  if (!tags.includes('cta_lead_page')) {
    tags.push('cta_lead_page');
  }
}

// -------------------------------------------------------------------
// 12.bis) Guardrail anti-USD / dólares
// -------------------------------------------------------------------
const replyLower2 = reply.toLowerCase();
const mentionsUsd = /\b(usd|u\$s|d[oó]lar(?:es)?|dolares|dólares)\b/.test(replyLower2);

if (mentionsUsd) {
  // Reescribimos a una respuesta segura en pesos / web pública
  reply =
    'Tiene todo el sentido que quieras ver los costos.\n' +
    'Para no marearte con números sueltos, los precios de NovaVision son públicos y los podés ver siempre actualizados en la página principal: https://novavision.lat.\n' +
    'Por lo que venimos charlando, mucha gente en una situación parecida a la tuya suele arrancar con un plan para emprendedores donde ya tenés tienda online, catálogo y cobros integrados.\n' +
    'Si querés, te ayudo a ver si ese plan te encaja y, si te cierra, coordinamos una demo corta para verlo aplicado a tu negocio.';

  if (!Array.isArray(tags)) tags = [];
  if (!tags.includes('price_question')) {
    tags.push('price_question');
  }
}


// -------------------------------------------------------------------
// 13) Limpiar muletillas y espacios raros
// -------------------------------------------------------------------
const muletillas = [
  /por lo que me cont[aá]s/gi,
  /entiendo que/gi,
  /veo que/gi,
  /tiene sentido lo que cont[aá]s/gi,
  /tiene sentido que/gi,
  /muchos que venden/gi,
  /muchos que usan/gi,
];

muletillas.forEach((re) => {
  reply = reply.replace(re, '');
});

// normalizar espacios y saltos de línea
reply = reply
  .replace(/[ \t]+/g, ' ')
  .replace(/\s*\n\s*/g, '\n')
  .trim();

// -------------------------------------------------------------------
// 14) Pequeño límite de longitud
// -------------------------------------------------------------------
if (reply.length > 800) {
  reply = reply.slice(0, 750) + '…\n¿Te hace sentido hasta acá?';
}

const aiStatus = $json.lead_status || 'WORKING';

let dbStatus;

// Mapeos IA → DB
switch (aiStatus) {
  case 'NEW':
    dbStatus = 'NEW';
    break;
  case 'CLIENT':
    dbStatus = 'CLIENT';
    break;
  case 'LOST':
    dbStatus = 'DISCARDED';
    break;
  // Todo lo que sea “estamos hablando / trabajando el lead”
  case 'WORKING':
  default:
    dbStatus = 'IN_CONVERSATION';
    break;
}

// Mapear conversationStage de la IA → valores aceptados por la DB
const allowedStages = [
  'INTRO',
  'DISCOVERY',
  'FOLLOWUP',
  'CLOSING',
  'DEMO_OFFERED',
  'DEMO_BOOKED',
];

let dbConversationStage = conversationStage || 'DISCOVERY';

// Tus etiquetas nuevas se normalizan acá
if (
  dbConversationStage === 'PROFUNDIZAR_DOLORES' ||
  dbConversationStage === 'PROFUNDIZAR DOLORES'
) {
  // Elegí a dónde querés mandarlo. Yo lo pondría como FOLLOWUP o DISCOVERY.
  dbConversationStage = 'DISCOVERY';
}

// Si viene cualquier otra cosa rara, fallback seguro
if (!allowedStages.includes(dbConversationStage)) {
  dbConversationStage = 'DISCOVERY';
}

// -------------------------------------------------------------------
// 15) Salida final normalizada
// -------------------------------------------------------------------
return {
  reply,
  lead_status: leadStatus,
  conversation_stage: conversationStage,
  pain_points: painPoints,
  interest_level: interestLevel,
  tags,
  next_followup_days: nextFollowupDays,
  db_status: dbStatus,
  db_conversation_stage: dbConversationStage,
};

