// Tomamos la respuesta cruda de dolarapi
const d = $json || {};

const fx = {
  source: 'dolarapi_blue',
  currency: 'ARS',
  usd_to_ars_blue_buy: Number(d.compra) || null,
  usd_to_ars_blue_sell: Number(d.venta) || null,
  updated_at: d.fechaActualizacion || null,
};

return {
  fx,
};

const base = $json;

// Si no es un mensaje válido (ej: solo status), cortamos el flujo acá.
if (base.valid_msg === false) {
  return []; // no sale ningún item → el workflow termina
}

let phoneForSend = base.phone_raw || '';

// Parche solo para Argentina sandbox: 54911xxxxxxxx -> 5411xxxxxxxx
if (typeof phoneForSend === 'string') {
  phoneForSend = phoneForSend.replace(/^54911/, '5411');
}

return {
  ...base,
  phone_raw: phoneForSend,
  phone: phoneForSend,
  phone_for_send: phoneForSend,
};

// Lee/crea storage global del workflow
const staticData = $getWorkflowStaticData('global');
if (!staticData.nvConfig) {
  staticData.nvConfig = {};
}

const now = Date.now();

// TTLs
const TTL_PLAYBOOK_MS = 12 * 60 * 60 * 1000;  // 12 horas
const TTL_PRICING_MS  = 12 * 60 * 60 * 1000;  // 12 horas
const TTL_FX_MS       = 10 * 60 * 1000;       // 10 minutos

const cfg = staticData.nvConfig;

function isFresh(ts, ttl) {
  if (!ts) return false;
  return (now - ts) < ttl;
}

const hasPlaybook = Array.isArray(cfg.playbook) && isFresh(cfg.playbookCachedAt, TTL_PLAYBOOK_MS);
const hasPricing  = Array.isArray(cfg.pricing)  && isFresh(cfg.pricingCachedAt, TTL_PRICING_MS);
const hasFx       = !!cfg.fx && isFresh(cfg.fxCachedAt, TTL_FX_MS);

return {
  has_playbook: hasPlaybook,
  has_pricing: hasPricing,
  has_fx: hasFx,
  playbook: hasPlaybook ? cfg.playbook : null,
  pricing:  hasPricing  ? cfg.pricing  : null,
  fx:       hasFx       ? cfg.fx       : null,
};

// Static data global
const staticData = $getWorkflowStaticData('global');
if (!staticData.nvConfig) {
  staticData.nvConfig = {};
}

// Traemos los outputs de los otros nodos
const playbookRows = $('Get NV Playbook').item.json || [];
const pricingRows  = $('Get NV Pricing').item.json || [];
const fxObj        = $('Prepare FX for AI').item.json.fx || null;

// Guardamos en cache
staticData.nvConfig = {
  playbook: playbookRows,
  pricing:  pricingRows,
  fx:       fxObj,
  playbookCachedAt: Date.now(),
  pricingCachedAt:  Date.now(),
  fxCachedAt:       Date.now(),
};

// Devolvemos lo que usará la IA
return {
  playbook: playbookRows,
  pricing:  pricingRows,
  fx:       fxObj,
};

// Rows crudos que vienen del cache o del save
const rawPlaybook = $json.playbook || [];
const rawPricing = $json.pricing || [];
const fx = $json.fx || null;

// Datos del lead para segmentar un poco
const lead = $node["Prepare Lead Data"].json || {};
const category = String(lead.category || '').toLowerCase();

// Podés usar campos de notas / último mensaje si los tenés
const notes = (
  (lead.notes || '') + ' ' +
  (lead.last_message || '') + ' ' +
  (lead.last_contact_notes || '')
).toLowerCase();

// Tags del lead si existen
const tags = Array.isArray(lead.tags)
  ? lead.tags.map((t) => String(t).toLowerCase())
  : [];

// Segmentos base (siempre)
const segments = new Set(['general', 'generic']);

// Heurística simple de segmento según rubro
if (category.includes('ropa') || category.includes('indumentaria')) {
  segments.add('tienda_ropa');
}

if (
  category.includes('gym') ||
  category.includes('gimnasio') ||
  category.includes('fitness')
) {
  segments.add('gym');
}

// Heurística para segmento de integraciones
// (ajustá estas palabras clave a gusto)
const needsIntegration =
  tags.includes('requires_integration') ||
  tags.includes('integraciones') ||
  notes.includes('integración') ||
  notes.includes('integraciones') ||
  notes.includes('erp') ||
  notes.includes('facturación') ||
  notes.includes('pos') ||
  (notes.includes('sistema') && notes.includes('stock'));

if (needsIntegration) {
  segments.add('requires_integration');
}

// Filtramos por segmento y active
const filtered = (Array.isArray(rawPlaybook) ? rawPlaybook : [])
  .filter((row) => {
    if (row.active === false) return false;
    const seg = row.segment || 'general';
    return segments.has(seg);
  })
  .sort((a, b) => (b.priority || 0) - (a.priority || 0)); // prioridad desc

// Agrupamos por type y recortamos cantidad por tipo
const byType = {};

for (const row of filtered) {
  const t = row.type || 'other';
  if (!byType[t]) byType[t] = [];

  // Máx 12 entradas por tipo para no explotar el contexto
  if (byType[t].length >= 12) continue;

  byType[t].push({
    key: row.key,
    segment: row.segment,
    stage: row.stage,
    type: row.type,
    topic: row.topic,
    title: row.title,
    content: row.content,
    priority: row.priority,
  });
}

return {
  playbook: byType,   // objeto agrupado por type
  pricing: rawPricing,
  fx,
};
